import{_ as i,o as e,c as n,a2 as l}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Pubblicazione","description":"","frontmatter":{},"headers":[],"relativePath":"it/guide/publishing.md","filePath":"it/guide/publishing.md"}'),o={name:"it/guide/publishing.md"};function s(t,a,r,c,d,p){return e(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="pubblicazione" tabindex="-1">Pubblicazione <a class="header-anchor" href="#pubblicazione" aria-label="Permalink to &quot;Pubblicazione&quot;">​</a></h1><p>Clearance pubblica tre tipi di asset tramite i tag <code>vendor:publish</code>: configurazione, migrazioni, e traduzioni. Configurazione e migrazioni sono gestite automaticamente dall&#39;installer (vedi <a href="/clearance-docs/it/guide/installation.html">Installation</a>); questa pagina copre la loro pubblicazione manuale, e la pubblicazione delle traduzioni.</p><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Pubblica <code>config/clearance.php</code> nella tua applicazione. Vedi il <a href="/clearance-docs/it/guide/configuration.html">riferimento di configurazione</a> per ogni chiave, il suo valore predefinito, e il suo scopo.</p><h2 id="traduzioni" tabindex="-1">Traduzioni <a class="header-anchor" href="#traduzioni" aria-label="Permalink to &quot;Traduzioni&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-translations</span></span></code></pre></div><p>Questo copia le 9 lingue incluse (<code>ar</code>, <code>en</code>, <code>es</code>, <code>fr</code>, <code>hi</code>, <code>it</code>, <code>pt</code>, <code>ru</code>, <code>zh</code>) in <code>lang/vendor/clearance/{locale}/ui.php</code> nella tua app. Per aggiungere una nuova lingua o sovrascrivere le stringhe in una esistente, aggiungi lì una directory per la lingua, usando <code>en/ui.php</code> come riferimento canonico delle chiavi. Tutte le lingue espongono un insieme identico di chiavi, verificato da un test dedicato ad ogni modifica.</p><h2 id="sovrascrivere-il-layout-del-pannello" tabindex="-1">Sovrascrivere il layout del pannello <a class="header-anchor" href="#sovrascrivere-il-layout-del-pannello" aria-label="Permalink to &quot;Sovrascrivere il layout del pannello&quot;">​</a></h2><p>La chiave di configurazione <code>layout</code> controlla il layout Blade usato dai componenti a pagina intera:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layout&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// host app&#39;s default (config(&#39;livewire.layout&#39;))</span></span></code></pre></div><p>Lasciala a <code>null</code> per usare il layout Livewire predefinito della tua applicazione, oppure impostala su una vista di layout specifica per renderizzare il pannello dentro una shell personalizzata.</p><h2 id="migrazioni" tabindex="-1">Migrazioni <a class="header-anchor" href="#migrazioni" aria-label="Permalink to &quot;Migrazioni&quot;">​</a></h2><p>Le migrazioni di Clearance vengono pubblicate ed eseguite automaticamente da <code>php artisan clearance:install</code> - l&#39;installer pubblica ed esegue anche le migrazioni di Spatie prima, se la tabella <code>roles</code> non esiste ancora. Vedi <a href="/clearance-docs/it/guide/installation.html">Installation</a> per il flusso completo passo-passo, e il <a href="/clearance-docs/it/guide/installation.html#run-the-installer">riquadro di pericolo</a> sul non eseguire mai una semplice <code>migrate</code> su un&#39;installazione nuova.</p><h2 id="correlati" tabindex="-1">Correlati <a class="header-anchor" href="#correlati" aria-label="Permalink to &quot;Correlati&quot;">​</a></h2><ul><li><a href="/clearance-docs/it/guide/configuration.html">Riferimento di configurazione</a> - ogni chiave di configurazione</li><li><a href="/clearance-docs/it/guide/installation.html">Installation</a> - il flusso completo dell&#39;installer</li><li><a href="/clearance-docs/it/guide/migration.html">Migration</a> - <code>clearance:backfill</code> per installazioni Spatie esistenti</li></ul>`,16)])])}const g=i(o,[["render",s]]);export{u as __pageData,g as default};
